namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a database or API call
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Hydraulic Press",     "Building A - Floor 1", new DateTime(2026, 3, 10)),
            new(2, "CNC Lathe",           "Building A - Floor 2", new DateTime(2026, 4, 22)),
            new(3, "Arc Welder",          "Building B - Bay 3",   new DateTime(2025, 12, 5)),
            new(4, "Forklift #7",         "Warehouse C",          new DateTime(2026, 5, 1)),
            new(5, "Overhead Crane",      "Building B - Bay 1",   new DateTime(2026, 1, 18)),
            new(6, "Band Saw",            "Building A - Floor 1", new DateTime(2026, 2, 28)),
            new(7, "Compressor Unit",     "Utility Room",         new DateTime(2025, 11, 15)),
            new(8, "Conveyor Belt #2",    "Warehouse C",          new DateTime(2026, 4, 9)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState PersistState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;
    private PersistingComponentStateSubscription persistSub;

    protected override async Task OnInitializedAsync()
    {
        // On the interactive render, try to restore persisted data first.
        // If found, skip the service call entirely — data was already fetched
        // during prerendering and serialized into the page.
        if (PersistState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            items = restored;
        }
        else
        {
            items = await EquipmentSvc.GetEquipmentAsync();
        }

        // During prerendering this callback is invoked to serialize state
        // into the HTML so the interactive render can pick it up.
        persistSub = PersistState.RegisterOnPersisting(() =>
        {
            PersistState.PersistAsJson("equipment", items);
            return Task.CompletedTask;
        });
    }

    public void Dispose() => persistSub.Dispose();
}

